var activeFilter = 'open';
var expandedPalletId = null;
var expandedMode = null; // 'view' | 'create'
var pallets = [];
var customers = [];
var currentPallet = {};
var currentItems = [];
var selectedCustomerId = null;
function fmt(d) {
  if (!d) return '—';
  var dt = new Date(d);
  if (isNaN(dt.getTime())) return String(d);
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function fmtUser(email) {
  if (!email) return '—';
  return String(email).split('@')[0];
}
function fmtCurrency(v) {
  if (v === null || v === undefined) return '—';
  return '£' + Number(v).toFixed(2);
}
function statusBadgeClass(s) {
  var cls = {
    open: 'badge-open',
    closed: 'badge-closed',
    shipped: 'badge-collected'
  };
  return cls[s] || 'badge-open';
}
function escHtml(str) {
  if (str === null || str === undefined) return '';
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// ---------- FILTER PILLS ----------
function renderFilterPills() {
  var counts = {
    all: pallets.length,
    open: 0,
    closed: 0,
    shipped: 0
  };
  pallets.forEach(function (p) {
    var s = p.status || 'open';
    if (counts[s] !== undefined) counts[s]++;
  });
  var defs = [{
    key: 'all',
    label: 'All'
  }, {
    key: 'open',
    label: 'Open'
  }, {
    key: 'closed',
    label: 'Closed'
  }, {
    key: 'shipped',
    label: 'Shipped'
  }];
  return '<div class="filter-row">' + defs.map(function (d) {
    var isActive = activeFilter === d.key;
    var cls = 'filter-pill' + (isActive ? ' active f-' + d.key : '');
    return '<div class="' + cls + '" data-filter="' + d.key + '">' + d.label + '<span class="cnt">' + counts[d.key] + '</span></div>';
  }).join('') + '</div>';
}

// ---------- CREATE PANEL ----------
function renderCreatePanel() {
  return '<div class="create-panel open">' + '<label>Select Customer</label>' + '<div class="search-select" id="customer_select_wrap">' + '<input type="text" id="customer_search" placeholder="Search customer..." autocomplete="off"/>' + '<div class="search-dropdown" id="customer_dropdown"></div>' + '<input type="hidden" id="customer_id_hidden"/>' + '</div>' + '<div class="form-actions">' + '<button class="btn btn-secondary" id="btn_cancel_create">Cancel</button>' + '<button class="btn btn-primary" id="btn_confirm_create">Create Pallet</button>' + '</div>' + '</div>';
}

// ---------- EXPANDED VIEW ----------
function renderViewPanel(p) {
  var itemsRows = !currentItems.length ? '<tr><td colspan="9" class="empty">No assets on this pallet yet</td></tr>' : currentItems.map(function (it) {
    var ref = it.asset_ref ? '<span class="result-ref">' + escHtml(it.asset_ref) + '</span>' : '—';
    var desc = [it.make_name, it.model_name].filter(Boolean).join(' ') || '—';
    return '<tr>' + '<td>' + ref + '</td>' + '<td>' + escHtml(it.serial_number || '—') + '</td>' + '<td>' + escHtml(desc) + '</td>' + '<td>' + escHtml(it.cpu || '—') + '</td>' + '<td>' + escHtml(it.ram || '—') + '</td>' + '<td style="font-weight:700;color:#05042E">' + fmtCurrency(it.sale_price) + '</td>' + '<td>' + fmtUser(it.added_by) + '</td>' + '<td>' + fmt(it.added_date) + '</td>' + '<td><button class="btn-sm btn-danger" data-item-id="' + it.item_id + '" data-action="delete-item">Remove</button></td>' + '</tr>';
  }).join('');
  return '<div class="expand-inner">' + '<div class="pallet-header">' + '<div class="header-top">' + '<div style="display:flex;align-items:center;gap:12px;">' + '<span class="pallet-ref">' + escHtml(p.pallet_ref || '—') + '</span>' + '<span class="badge ' + statusBadgeClass(p.status) + '">' + escHtml(p.status || 'open') + '</span>' + '</div>' + '<div class="header-actions">' + '<button class="btn btn-danger-outline" id="btn_close_pallet">Close Pallet</button>' + '<button class="btn btn-secondary" id="btn_close_expand">Close</button>' + '</div>' + '</div>' + '<div class="meta-grid">' + '<div class="meta-item"><span class="meta-label">Customer</span><span class="meta-value">' + escHtml(p.customer_name || 'No customer assigned') + '</span></div>' + '<div class="meta-item"><span class="meta-label">Total Value</span><span class="meta-value total">' + fmtCurrency(p.total_value) + '</span></div>' + '<div class="meta-item"><span class="meta-label">Assets</span><span class="meta-value">' + (p.item_count || 0) + ' asset(s)</span></div>' + '<div class="meta-item"><span class="meta-label">Created</span><span class="meta-value">' + fmt(p.created_date) + '</span></div>' + '</div>' + '</div>' + '<div class="price-bar">' + '<div>' + '<div class="field-label">Total Pallet Sale Price (£)</div>' + '<div style="display:flex;gap:8px;align-items:center;">' + '<input class="field-input" id="f_total_price" type="number" min="0" step="0.01" placeholder="0.00" style="width:160px;">' + '<button class="btn btn-secondary" id="btn_apply_price">Apply Equal Split</button>' + '</div>' + '<div class="split-preview" id="split_preview"></div>' + '</div>' + '<button class="btn-process" id="btn_process_order">✓ Process as Sale Order</button>' + '</div>' + '<div class="scan-bar">' + '<div class="field-label" style="margin-bottom:6px;">Scan or type exact asset ref / serial, then press Enter</div>' + '<div style="position:relative;">' + '<input class="field-input" id="f_scan" type="text" placeholder="Scan barcode or type full ref, then Enter" autocomplete="off" style="width:100%;">' + '</div>' + '</div>' + '<div class="section-header"><span class="section-title">Assets on Pallet</span></div>' + '<table><thead><tr><th>Ref</th><th>Serial</th><th>Make / Model</th><th>CPU</th><th>RAM</th><th>Sale Price</th><th>Added By</th><th>Date</th><th></th></tr></thead>' + '<tbody>' + itemsRows + '</tbody></table>' + '</div>';
}

// ---------- MAIN LIST ----------
function renderList() {
  var filtered = activeFilter === 'all' ? pallets : pallets.filter(function (p) {
    return (p.status || 'open') === activeFilter;
  });
  var rowsHtml;
  if (!filtered.length) {
    rowsHtml = '<tr><td colspan="7" class="empty">No sale pallets in this view</td></tr>';
  } else {
    rowsHtml = filtered.map(function (p) {
      var mainRow = '<tr>' + '<td><span class="pallet-ref">' + escHtml(p.pallet_ref || '—') + '</span></td>' + '<td><span class="badge ' + statusBadgeClass(p.status) + '">' + escHtml(p.status || 'open') + '</span></td>' + '<td>' + (p.customer_name ? escHtml(p.customer_name) : '<span style="color:#888780">—</span>') + '</td>' + '<td>' + fmtCurrency(p.total_value) + '</td>' + '<td>' + (p.item_count || 0) + '</td>' + '<td style="font-size:11px">' + fmt(p.created_date) + '</td>' + '<td><button class="btn-sm btn-view" data-pallet-id="' + p.pallet_id + '" data-action="view">View</button></td>' + '</tr>';
      var expandHtml = '';
      if (expandedPalletId === p.pallet_id && expandedMode === 'view') {
        expandHtml = '<tr class="expand-row"><td colspan="7">' + renderViewPanel(p) + '</td></tr>';
      }
      return mainRow + expandHtml;
    }).join('');
  }
  var createRow = expandedMode === 'create' ? '<tr class="expand-row"><td colspan="7">' + renderCreatePanel() + '</td></tr>' : '';
  return '<div class="card">' + '<div class="card-header"><span class="card-title">Sale Pallets</span>' + '<button class="btn btn-primary" id="btn_new_pallet">+ New Pallet</button></div>' + renderFilterPills() + createRow + '<table><thead><tr><th>Pallet Ref</th><th>Status</th><th>Customer</th><th>Total Value</th><th>Assets</th><th>Created</th><th></th></tr></thead>' + '<tbody>' + rowsHtml + '</tbody></table></div>';
}

// ---------- WIRING ----------
function wireEvents() {
  document.querySelectorAll('[data-filter]').forEach(function (el) {
    el.addEventListener('click', function () {
      activeFilter = this.dataset.filter;
      renderAll(appsmith.model);
    });
  });
  var newBtn = document.getElementById('btn_new_pallet');
  if (newBtn) newBtn.addEventListener('click', function () {
    expandedPalletId = null;
    expandedMode = 'create';
    selectedCustomerId = null;
    renderAll(appsmith.model);
  });
  if (expandedMode === 'create') {
    var custInput = document.getElementById('customer_search');
    var custDropdown = document.getElementById('customer_dropdown');
    function renderCustomerOptions(filter) {
      var filtered = filter ? customers.filter(function (c) {
        return c.customer_name.toLowerCase().indexOf(filter.toLowerCase()) > -1;
      }) : customers;
      if (!filtered.length) {
        custDropdown.innerHTML = '<div class="search-option no-results">No customers found</div>';
      } else {
        custDropdown.innerHTML = filtered.map(function (c) {
          return '<div class="search-option" data-id="' + c.customer_id + '" data-label="' + escHtml(c.customer_name) + '">' + escHtml(c.customer_name) + '</div>';
        }).join('');
        custDropdown.querySelectorAll('.search-option[data-id]').forEach(function (el) {
          el.addEventListener('click', function () {
            selectedCustomerId = this.dataset.id;
            custInput.value = this.dataset.label;
            document.getElementById('customer_id_hidden').value = selectedCustomerId;
            custDropdown.classList.remove('open');
          });
        });
      }
      custDropdown.classList.add('open');
    }
    if (custInput) {
      custInput.addEventListener('focus', function () {
        renderCustomerOptions(this.value);
      });
      custInput.addEventListener('input', function () {
        renderCustomerOptions(this.value);
      });
    }
    var cancelCreateBtn = document.getElementById('btn_cancel_create');
    if (cancelCreateBtn) cancelCreateBtn.addEventListener('click', function () {
      expandedMode = null;
      renderAll(appsmith.model);
    });
    var confirmCreateBtn = document.getElementById('btn_confirm_create');
    if (confirmCreateBtn) confirmCreateBtn.addEventListener('click', function () {
      if (!selectedCustomerId) {
        alert('Please select a customer');
        return;
      }
      appsmith.updateModel({
        new_pallet_customer_id: Number(selectedCustomerId)
      });
      appsmith.triggerEvent('onCreatePallet');
      expandedMode = null;
    });
  }
  document.querySelectorAll('[data-action="view"]').forEach(function (btn) {
    btn.addEventListener('click', function () {
      var id = Number(this.dataset.palletId);
      if (expandedPalletId === id && expandedMode === 'view') {
        expandedPalletId = null;
        renderAll(appsmith.model);
        return;
      }
      expandedPalletId = id;
      expandedMode = 'view';
      appsmith.updateModel({
        selectedPalletId: id
      });
      appsmith.triggerEvent('onSelectPallet');
      renderAll(appsmith.model);
    });
  });
  if (expandedMode === 'view' && expandedPalletId !== null) {
    var closeExpandBtn = document.getElementById('btn_close_expand');
    if (closeExpandBtn) closeExpandBtn.addEventListener('click', function () {
      expandedPalletId = null;
      renderAll(appsmith.model);
    });
    var closePalletBtn = document.getElementById('btn_close_pallet');
    if (closePalletBtn) closePalletBtn.addEventListener('click', function () {
      if (!confirm('Close this pallet without processing as a sale?')) return;
      appsmith.updateModel({
        selectedPalletId: expandedPalletId
      });
      appsmith.triggerEvent('onClosePallet');
    });
    var scanInput = document.getElementById('f_scan');
    if (scanInput) scanInput.addEventListener('keydown', function (e) {
      if (e.key !== 'Enter') return;
      e.preventDefault();
      var val = this.value.trim();
      if (!val) return;
      appsmith.updateModel({
        scan_value: val,
        selectedPalletId: expandedPalletId
      });
      appsmith.triggerEvent('onScanAsset');
      this.value = '';
    });
    var applyPriceBtn = document.getElementById('btn_apply_price');
    if (applyPriceBtn) applyPriceBtn.addEventListener('click', function () {
      var total = parseFloat(document.getElementById('f_total_price').value);
      var count = currentItems.length;
      if (!total || total <= 0) {
        alert('Enter a valid total price');
        return;
      }
      if (!count) {
        alert('Add assets to the pallet first');
        return;
      }
      var perAsset = (total / count).toFixed(2);
      document.getElementById('split_preview').textContent = count + ' asset(s) × £' + perAsset + ' each = £' + total.toFixed(2) + ' total';
      appsmith.updateModel({
        selectedPalletId: expandedPalletId,
