          appsmith.triggerEvent('onDeleteItem');
        });
      });
    }
  }

  // ---------- MAIN RENDER ----------
  function renderAll(model) {
    var m = model || {};
    pallets = m.pallets || [];
    customers = m.customers || [];
    currentPallet = m.pallet || {};
    currentItems = m.items || [];

    var root = document.getElementById('root');
    root.innerHTML = renderList();
    wireEvents();
  }

  function initWhenReady() {
    if (typeof appsmith === 'undefined' || !appsmith.onReady) {
      setTimeout(initWhenReady, 50);
      return;
    }
    appsmith.onReady(() => renderAll(appsmith.model));
    appsmith.onModelChange(() => renderAll(appsmith.model));
  }

  initWhenReady();
